const results = [];

for (const item of $input.all()) {
  const data = item.json;

  // Apify format
  if (data.url && data.url.includes('linkedin.com')) {
    let profileUrl = data.authorProfileUrl || '';
    if (profileUrl.includes('?')) {
      profileUrl = profileUrl.split('?')[0];
    }
    profileUrl = profileUrl.replace(/\/$/, '').toLowerCase();

    if (data.authorType === 'Company') continue;

    const likes = parseInt(data.numLikes) || 0;
    const comments = parseInt(data.numComments) || 0;
    const shares = parseInt(data.numShares) || 0;

    results.push({
      post_url: data.url,
      author_name: data.authorName || 'Unknown',
      author_headline: data.authorHeadline || data.author?.occupation || '',
      author_linkedin_url: profileUrl,
      company: '',
      post_snippet: (data.text || '').substring(0, 300),
      source: 'apify',
      keyword_matched: data.inputUrl ?
        decodeURIComponent(data.inputUrl).match(/keywords=([^&]*)/)?.[1] || 'apify_search'
        : 'apify_search',
      author_type: data.authorType || 'Unknown',
      numLikes: likes,
      numComments: comments,
      numShares: shares,
      engagement_score: likes + (comments * 3) + (shares * 2)
    });
  }
}

return results.map(r => ({ json: r }));

const newPosts = $('Normalize Results').all().map(i => i.json);
const seenPosts = $('Read Already Seen').all().map(i => i.json);
const seenUrls = new Set(seenPosts.map(p => p.post_url));

const unseen = newPosts.filter(p => !seenUrls.has(p.post_url));

return unseen.map(r => ({ json: r }));

const posts = $('Deduplicate').all().map(i => i.json);
const icpList = $('Read ICP List').all().map(i => i.json);

const icpUrls = new Set(
  icpList.map(c => c.linkedin_profile_url?.toLowerCase().replace(/\/$/, ''))
);

const goodTitles = [
  'vp', 'svp', 'vice president', 'director', 'senior manager',
  'head of', 'chief', 'cmo', 'cso', 'strategy', 'strategic planning',
  'market research', 'market intelligence', 'consumer insights',
  'competitive intelligence', 'business intelligence', 'corporate development',
  'marketing', 'business development', 'product development', 'product strategy',
  'policy', 'growth', 'innovation', 'commercial', 'insights', 'research'
];

const badTitles = [
  'student', 'intern', 'coordinator', 'ux research', 'user research',
  'recruiter', 'talent', 'hr ', 'human resources', 'software engineer',
  'developer', 'looking for opportunities', 'seeking', 'aspiring',
  'freelancer', 'looking for work', 'open to work'
];

const negativeKeywords = [
  'survey tool', 'survey platform', 'survey software', 'focus group recruitment',
  'nps score', 'a/b test', 'a/b testing', 'ux research', 'user testing',
  'qualtrics', 'surveymonkey', 'typeform', 'customer satisfaction survey',
  'influencer marketing', 'content creator'
];

const reportSpamSignals = [
  'cagr', 'sample copy', 'forecast period', 'market size was valued',
  'request a sample', 'limited-time special discount',
  'market reached a valuation', 'market report',
  'well-research report', 'get well-research report'
];

const tier1Keywords = [
  'looking for market data', 'need industry data', 'market sizing',
  'go to market', 'go-to-market', 'entering a new market', 'market expansion',
  'competitive landscape', 'industry analysis', 'does anyone know',
  'recommendations for', 'strategic planning process', 'starting our strategic plan',
  'evidence-based', 'data to support', 'market intelligence', 'marketing intelligence'
];

const tier2Keywords = [
  'strategic planning', 'pestle', 'pestel', 'environmental scan',
  'sector analysis', 'market scan', 'market landscape', 'competitive analysis',
  'new market opportunity', 'diversification strategy', 'capital investment',
  'board presentation', 'voice of the customer', 'product-market fit',
  'business case', 'market validation', 'market feasibility', 'due diligence'
];

const scored = [];

for (const post of posts) {
  const headline = (post.author_headline || '').toLowerCase();
  const snippet = (post.post_snippet || '').toLowerCase();
  const authorUrl = (post.author_linkedin_url || '').toLowerCase().replace(/\/$/, '');

  const icpMatch = icpUrls.has(authorUrl);

  const hasBillionOrUsd = snippet.includes('billion') || snippet.includes('usd ');
  const hasReportSpam = reportSpamSignals.some(s => snippet.includes(s));
  if (hasBillionOrUsd && hasReportSpam) continue;
  const reportSpamCount = reportSpamSignals.filter(s => snippet.includes(s)).length;
  if (reportSpamCount >= 2) continue;

  const totalEngagement = (post.engagement_score || 0);
  const numLikes = parseInt(post.numLikes) || 0;
  const numComments = parseInt(post.numComments) || 0;
  const rawEngagement = numLikes + numComments;
  if (!icpMatch && rawEngagement === 0 && totalEngagement === 0) continue;

  const negHits = negativeKeywords.filter(k => snippet.includes(k));
  if (negHits.length > 0) continue;

  const hasBadTitle = badTitles.some(t => headline.includes(t));
  if (hasBadTitle) continue;

  let score = 0;
  let tier = 3;
  let matchedKeywords = [];

  if (icpMatch) score += 5;

  const hasGoodTitle = goodTitles.some(t => headline.includes(t));
  if (hasGoodTitle) score += 2;

  const t1Hits = tier1Keywords.filter(k => snippet.includes(k));
  if (t1Hits.length > 0) {
    score += 3;
    tier = 1;
    matchedKeywords.push(...t1Hits);
  }

  const t2Hits = tier2Keywords.filter(k => snippet.includes(k));
  if (t2Hits.length > 0 && tier > 2) {
    score += 2;
    tier = 2;
    matchedKeywords.push(...t2Hits);
  }

  if (icpMatch && tier > 1) tier = 1;

  if (rawEngagement > 50) score += 1;
  if (rawEngagement > 200) score += 1;

  if (score < 2) continue;

  scored.push({
    ...post,
    relevance_score: score,
    tier: tier,
    icp_list_match: icpMatch ? 'Yes' : 'No',
    keyword_matched: matchedKeywords.join(', ') || post.keyword_matched,
    date_found: new Date().toISOString().split('T')[0]
  });
}

scored.sort((a, b) => a.tier - b.tier || b.relevance_score - a.relevance_score);
const capped = scored.slice(0, 20);

return capped.map(r => ({ json: r }));

const posts = $input.all().map(i => i.json);

if (posts.length === 0) return [];

const postSummaries = posts.map((p, i) => 
  `Post ${i + 1}:\nAuthor: ${p.author_name}\nHeadline: ${p.author_headline}\nSnippet: ${p.post_snippet}\nKeywords matched: ${p.keyword_matched}\nICP match: ${p.icp_list_match}`
).join('\n\n---\n\n');

const systemPrompt = `You are a lead qualification assistant for a boutique market intelligence and research consultancy. The firm helps organizations with strategic planning, market sizing, competitive analysis, industry research, and market validation.

Evaluate each LinkedIn post and determine if the author is likely a potential buyer of market research or strategy consulting services.

Rate each post as:
- HOT: Author is actively seeking market data, research support, or strategy consulting. Shows clear buying intent or pain point the firm could solve.
- WARM: Author is in a relevant role discussing relevant topics, but no clear immediate buying signal. Worth engaging for relationship building.
- COLD: Author is a vendor/competitor selling similar services, a student/academic, sharing generic thought leadership with no buying context, or posting syndicated content.

Respond ONLY with a JSON array. No markdown, no backticks, no preamble. Each element must have:
- "index": the post number (1-based)
- "rating": "HOT", "WARM", or "COLD"
- "reason": one sentence explaining your rating`;

const userPrompt = `Evaluate these ${posts.length} LinkedIn posts:\n\n${postSummaries}`;

try {
  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://openrouter.ai/api/v1/chat/completions',
    headers: {
      'Authorization': 'Bearer YOUR_OPENROUTER_API_KEY',
      'Content-Type': 'application/json'
    },
    body: {
      model: 'google/gemini-2.5-flash',
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: userPrompt }
      ],
      temperature: 0.1,
      max_tokens: 2000
    },
    json: true
  });

  const content = response.choices[0].message.content.trim();
  const cleaned = content.replace(/```json|```/g, '').trim();
  const ratings = JSON.parse(cleaned);

  const qualified = [];
  for (const rating of ratings) {
    const idx = rating.index - 1;
    if (idx < 0 || idx >= posts.length) continue;
    if (rating.rating === 'COLD') continue;

    qualified.push({
      ...posts[idx],
      llm_rating: rating.rating,
      llm_reason: rating.reason
    });
  }

  qualified.sort((a, b) => {
    if (a.llm_rating === 'HOT' && b.llm_rating !== 'HOT') return -1;
    if (a.llm_rating !== 'HOT' && b.llm_rating === 'HOT') return 1;
    return b.relevance_score - a.relevance_score;
  });

  return qualified.map(r => ({ json: r }));

} catch (err) {
  return posts.map(p => ({ json: { ...p, llm_rating: 'UNSCORED', llm_reason: 'LLM call failed: ' + err.message } }));
}
